  CLASS
	NAME "Modelo MIHR - Escenario A1B"
    EXPRESSION ([pixel] = -99999)
    COLOR -1 -1 -1
  END
  CLASS
	NAME " "
    EXPRESSION ([pixel] = -9999)
    COLOR -1 -1 -1
  END
  CLASS
	NAME "Anomalía de pp (%)"
    EXPRESSION ([pixel] = -999)
    COLOR -1 -1 -1
  END
  CLASS
	NAME "-10.5 - -10.0"
    EXPRESSION ([pixel] >= -15.5 AND [pixel] < -10.0)
    COLOR 243 255 20
  END
  CLASS
