    COLOR 44 150 69
  END
  CLASS
	NAME "-8.5 - -8.0"
    EXPRESSION ([pixel] >= -8.5 AND [pixel] < -8.0)
    COLOR 80 196 51
  END
  CLASS
	NAME "-8.0 - -7.5"
    EXPRESSION ([pixel] >= -8.0 AND [pixel] < -7.5)
    COLOR 25 230 168
  END
  CLASS
	NAME "-7.5 - -7.0"
    EXPRESSION ([pixel] >= -7.5 AND [pixel] < -7.0)
    COLOR 0 168 132
  END
  CLASS
	NAME "-7.0 - -5.7"
    EXPRESSION ([pixel] >= -7.0 AND [pixel] <= -5.7)
    COLOR 41 248 255
